  const { totalItems } = useCart();
  const location = useLocation();

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Cardápio', path: '/cardapio' },
    { name: 'Sobre', path: '/sobre' },
    { name: 'Contato', path: '/contato' },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-charcoal/95 backdrop-blur-md border-b border-white/5">
      <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2 group">
          <div className="w-10 h-10 bg-ember rounded-lg flex items-center justify-center transition-transform group-hover:rotate-12">
            <Flame className="text-white w-6 h-6" />
          </div>
          <span className="text-xl font-serif font-bold tracking-tight text-white">
            Tudo na <span className="text-ember">Brasa</span>
          </span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              className={`text-sm font-medium transition-colors hover:text-ember ${
                isActive(link.path) ? 'text-ember' : 'text-gray-300'
              }`}
            >
              {link.name}
            </Link>
          ))}
        </nav>

        {/* Actions */}
        <div className="flex items-center gap-4">
          <button
            onClick={onCartOpen}
            className="relative p-2 text-gray-300 hover:text-ember transition-colors"
          >
            <ShoppingCart className="w-6 h-6" />
            {totalItems > 0 && (
              <span className="absolute top-0 right-0 bg-ember text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-charcoal">
                {totalItems}
              </span>
            )}
